import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { X, Minus, Plus, Trash2 } from 'lucide-react';
import { Wallet } from '@mercadopago/sdk-react';
import axios from 'axios';
import toast from 'react-hot-toast';

export default function CartModal() {
    const [preferenceId, setPreferenceId] = useState(null);
    const { isCartOpen, setIsCartOpen, cartItems, updateQuantity, removeFromCart, cartTotal, clearCart, fetchCart } = useCart();

    const navigate = useNavigate();

    if (!isCartOpen) return null;

    const handleCheckout = () => {
        setIsCartOpen(false);
        navigate('/checkout');
    };

    return (
        <div className="fixed inset-0 z-50 flex justify-end">
            <div
                className="absolute inset-0 bg-black bg-opacity-50 transition-opacity"
                onClick={() => setIsCartOpen(false)}
            />

            <div className="relative w-full max-w-md h-full bg-gusli-bg shadow-xl flex flex-col pt-6 transform transition-transform duration-300 ease-in-out sm:max-w-md">
                <div className="flex items-center justify-between px-6 pb-4 border-b border-black">
                    <h2 className="text-xl font-bold text-black">Seu Carrinho</h2>
                    <button onClick={() => setIsCartOpen(false)} className="text-black hover:text-black transition-colors">
                        <X size={24} />
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto p-6 flex flex-col gap-6">
                    {cartItems.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-black">
                            <p>Seu carrinho est├í vazio.</p>
                            <button
                                onClick={() => setIsCartOpen(false)}
                                className="mt-4 text-black underline"
                            >
                                Continuar Comprando
                            </button>
                        </div>
                    ) : (
                        cartItems.map((item, index) => (
                            <div key={index} className="flex gap-4 p-4 border rounded-xl border-black bg-white">
                                <img
                                    src={`http://localhost:3001${item.product.image_path}`}
                                    alt={item.product.name}
                                    className="w-20 h-28 object-cover rounded shadow-sm"
                                    onError={(e) => { e.target.src = 'https://placehold.co/100x150/png?text=No+Cover' }}
                                />

                                <div className="flex-1 flex flex-col justify-between">
                                    <div>
                                        <h3 className="font-bold text-black line-clamp-2 leading-tight">{item.product.name}</h3>
                                        {item.variation && <p className="text-sm text-black mt-1">Variante: {item.variation}</p>}
                                        <p className="text-sm text-black">{item.product.author}</p>
                                    </div>

                                    <div className="flex items-center justify-between mt-4">
                                        <div className="flex items-center gap-2 bg-gusli-bg rounded-lg p-1 border border-black">
                                            <button
                                                onClick={() => updateQuantity(item.product.id, item.variation, item.quantity - 1)}
                                                disabled={item.quantity <= 1}
                                                className="p-1 rounded text-black hover:bg-black disabled:opacity-50 transition-colors"
                                            >
                                                <Minus size={16} />
                                            </button>
                                            <span className="w-6 text-center text-sm font-medium">{item.quantity}</span>
                                            <button
                                                onClick={() => updateQuantity(item.product.id, item.variation, item.quantity + 1)}
                                                disabled={item.quantity >= 10}
                                                className="p-1 rounded text-black hover:bg-black disabled:opacity-50 transition-colors"
                                            >
                                                <Plus size={16} />
                                            </button>
                                        </div>

                                        <button
                                            onClick={() => removeFromCart(item.product.id, item.variation)}
                                            className="text-red-500 hover:text-black bg-red-50 hover:bg-red-600 border border-red-100 hover:border-red-600 p-2 rounded-lg transition-colors flex items-center justify-center shadow-sm"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>

                {cartItems.length > 0 && !preferenceId && (
                    <div className="p-6 border-t border-black bg-white">
                        <div className="flex flex-col gap-4 mb-6">
                            <div className="flex justify-between items-center bg-white p-4 rounded-xl border border-gray-100">
                                <span className="text-black font-bold uppercase tracking-widest text-xs">Total do Pedido</span>
                                <span className="text-2xl font-black text-black">R$ {cartTotal.toFixed(2)}</span>
                            </div>
                        </div>

                        <div className="flex flex-col gap-3">
                            <button
                                onClick={handleCheckout}
                                className="w-full bg-black text-gusli-bg py-4 rounded-full font-bold hover:bg-white hover:text-[#12271D] hover:border-[#12271D] border border-transparent hover:scale-[1.02] transform transition-all shadow-md flex justify-center items-center gap-2 uppercase tracking-wider text-sm"
                            >
                                Revisar & Pagar Pedido
                            </button>
                        </div>
                    </div>
                )}

            </div>
        </div>
    );
}

import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { ShoppingBag, ChevronDown } from 'lucide-react';
import { useState, useEffect } from 'react';
import axios from 'axios';

export default function Header() {
    const { cartItems, setIsCartOpen } = useCart();
    const itemCount = cartItems.reduce((acc, item) => acc + item.quantity, 0);
    const [genres, setGenres] = useState([]);
    const [scrolled, setScrolled] = useState(false);
    const navigate = useNavigate();

    // We can remove scrolled state logic as header is strictly set to #12271D now

    useEffect(() => {
        const fetchGenres = async () => {
            try {
                const response = await axios.get('http://localhost:3001/api/products');
                const uniqueGenres = new Set(response.data.map(b => b.genre).filter(Boolean));
                setGenres(Array.from(uniqueGenres).sort());
            } catch (error) {
                console.error("Error fetching genres for header:", error);
            }
        };
        fetchGenres();
    }, []);

    const handleGenreSelect = (genre) => {
        navigate(`/products?genre=${encodeURIComponent(genre)}`);
    };

    return (
        <header className="fixed w-full top-0 z-40 bg-gusli-green border-b border-black/20 py-4 shadow-md">
            <div className="max-w-[1600px] mx-auto px-6 h-12 flex items-center justify-between">

                {/* Typographic Logo */}
                <Link to="/" className="flex items-center gap-4 group">
                    <img src="http://localhost:3001/visual/logo.png" alt="Gusli Logo" className="h-8 md:h-12 w-auto object-contain" />
                    <span className="font-sans font-bold text-2xl tracking-tight text-white group-hover:text-gusli-bg transition-colors duration-300 hidden sm:block">Gusli Books</span>
                </Link>

                <nav className="flex items-center gap-10">
                    {/* Dropdown Navigation */}
                    <div className="relative group">
                        <Link to="/products" className="flex items-center gap-1.5 text-white font-bold py-4 hover:text-gusli-bg transition-colors text-sm">
                            Loja <ChevronDown size={14} className="mt-0.5 group-hover:rotate-180 transition-transform duration-300" />
                        </Link>
                        {/* Dropdown Menu */}
                        <div className="absolute top-full right-1/2 translate-x-1/2 w-48 bg-white rounded-xl shadow-xl border border-gray-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-300 flex flex-col py-2 z-50">
                            {genres.map(genre => (
                                <button
                                    key={genre}
                                    onClick={() => handleGenreSelect(genre)}
                                    className="px-4 py-2 text-left text-sm text-black hover:bg-white hover:text-black hover:font-bold transition-colors"
                                >
                                    {genre}
                                </button>
                            ))}
                            <div className="border-t border-gray-100 mt-2 pt-2">
                                <Link to="/products" className="block px-4 py-2 text-sm text-center font-bold text-black hover:bg-white hover:text-gusli-green transition-colors">
                                    Ver Todos
                                </Link>
                            </div>
                        </div>
                    </div>

                    <div className="hidden sm:flex items-center gap-6">
                        <Link to="/contact" className="text-white hover:text-gusli-bg transition-colors text-sm font-bold">
                            Informa├º├╡es
                        </Link>
                        <Link to="/account" className="text-white hover:text-gusli-bg transition-colors text-sm font-bold">
                            Conta
                        </Link>
                    </div>

                    <div className="flex items-center gap-6 ml-4 pl-6 border-l border-white/30">
                        <button
                            onClick={() => setIsCartOpen(true)}
                            className="relative flex items-center gap-2 group"
                            aria-label="Open cart"
                        >
                            <span className="text-sm font-bold text-white group-hover:text-gusli-bg transition-colors hidden sm:block">Carrinho</span>
                            <div className="relative">
                                <ShoppingBag size={20} className="text-white group-hover:text-gusli-bg transition-colors" strokeWidth={1.5} />
                                {itemCount > 0 && (
                                    <span className="absolute -top-1.5 -right-2 bg-red-600 text-black text-[10px] font-bold w-4 h-4 flex items-center justify-center rounded-full">
                                        {itemCount}
                                    </span>
                                )}
                            </div>
                        </button>
                    </div>
                </nav>
            </div>
        </header>
    );
}

import { createContext, useContext, useState, useEffect } from 'react';
import toast from 'react-hot-toast';
import axios from 'axios';

const CartContext = createContext();

export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
    const [cartItems, setCartItems] = useState(() => {
        const saved = localStorage.getItem('gusli_cart');
        return saved ? JSON.parse(saved) : [];
    });

    const [isCartOpen, setIsCartOpen] = useState(false);

    useEffect(() => {
        localStorage.setItem('gusli_cart', JSON.stringify(cartItems));
    }, [cartItems]);

    const addToCart = async (product, quantity = 1, variation = null) => {
        try {
            if (quantity < 1 || quantity > 10) {
                toast.error('A quantidade deve ser entre 1 e 10 unidades.');
                return;
            }

            const existingItem = cartItems.find(item => item.product.id === product.id && (item.variation === variation || (!item.variation && !variation)));

            if (existingItem) {
                if (existingItem.quantity + quantity > 10) {
                    toast.error('O limite m├íximo ├⌐ de 10 unidades por pedido.');
                    return;
                }
                const newQuantity = existingItem.quantity + quantity;
                setCartItems(cartItems.map(item =>
                    (item.product.id === product.id && (item.variation === variation || (!item.variation && !variation))) ? { ...item, quantity: newQuantity } : item
                ));
            } else {
                setCartItems([...cartItems, { product, quantity, variation }]);
            }
            toast.success('Produto adicionado ├á sacola!');
            setIsCartOpen(true);
        } catch (err) {
            toast.error('Falha ao adicionar ao carrinho.');
            console.error(err);
        }
    };

    const updateQuantity = async (productId, variation, newQuantity) => {
        try {
            if (newQuantity < 1) return;
            if (newQuantity > 10) {
                toast.error('O limite m├íximo ├⌐ de 10 unidades por pedido.');
                return;
            }
            setCartItems(cartItems.map(item =>
                (item.product.id === productId && (item.variation === variation || (!item.variation && !variation))) ? { ...item, quantity: newQuantity } : item
            ));
        } catch (err) {
            toast.error('Falha ao atualizar quantidade.');
        }
    };

    const removeFromCart = async (productId, variation) => {
        try {
            setCartItems(cartItems.filter(item => !(item.product.id === productId && (item.variation === variation || (!item.variation && !variation)))));
            toast.success('Produto removido da sacola.');
        } catch (err) {
            toast.error('Falha ao remover produto.');
        }
    };

    const clearCart = async () => {
        try {
            // Keep checkout sync
            setCartItems([]);
            localStorage.removeItem('gusli_cart');
            toast.success('Compra finalizada com sucesso!', { duration: 4000, icon: '≡ƒÄë' });
            setIsCartOpen(false);
        } catch (err) {
            toast.error('Erro ao finalizar compra.');
            console.error(err);
        }
    };

    const cartTotal = cartItems.reduce((total, item) => total + (item.product.price * item.quantity), 0);

    return (
        <CartContext.Provider value={{ cartItems, addToCart, updateQuantity, removeFromCart, clearCart, isCartOpen, setIsCartOpen, cartTotal }}>
            {children}
        </CartContext.Provider>
    );
};

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import axios from 'axios';
import toast from 'react-hot-toast';
import { ShieldCheck, ArrowLeft, ArrowRight } from 'lucide-react';

export default function Checkout() {
    const { cartItems, cartTotal, clearCart } = useCart();
    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(false);

    const [formData, setFormData] = useState({
        fullName: '',
        email: '',
        cpf: '',
        zipCode: '',
        street: '',
        number: '',
        complement: '',
        neighborhood: '',
        city: '',
        state: ''
    });

    if (cartItems.length === 0) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center bg-gusli-bg  group/page">

                <h2 className="font-display text-5xl md:text-7xl text-black mb-8 uppercase tracking-tighter">O arquivo est├í vazio.</h2>
                <button
                    onClick={() => navigate('/products')}
                    className="text-black uppercase tracking-[0.3em] font-bold text-xs hover:text-black transition-colors  border-b border-black/30 pb-1"
                >
                    [ Retornar ao Acervo ]
                </button>
            </div>
        );
    }

    const handleChange = (e) => {
        let value = e.target.value;
        if (e.target.name === 'cpf') {
            value = value.replace(/\D/g, '').replace(/(\d{3})(\d)/, '$1.$2').replace(/(\d{3})(\d)/, '$1.$2').replace(/(\d{3})(\d{1,2})/, '$1-$2').replace(/(-\d{2})\d+?$/, '$1');
        }
        if (e.target.name === 'zipCode') {
            value = value.replace(/\D/g, '').replace(/(\d{5})(\d)/, '$1-$2').replace(/(-\d{3})\d+?$/, '$1');
        }
        setFormData({ ...formData, [e.target.name]: value });
    };

    const handleZipCodeBlur = async (e) => {
        const cep = e.target.value.replace(/\D/g, '');
        if (cep.length === 8) {
            try {
                const res = await axios.get(`https://viacep.com.br/ws/${cep}/json/`);
                if (!res.data.erro) {
                    setFormData(prev => ({
                        ...prev,
                        street: res.data.logradouro || '',
                        neighborhood: res.data.bairro || '',
                        city: res.data.localidade || '',
                        state: res.data.uf || ''
                    }));
                } else {
                    toast.error("CEP n├úo encontrado.");
                }
            } catch (err) {
                toast.error("Erro ao buscar integra├º├úo com os Correios.");
            }
        }
    };

    const isValidEmail = (email) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

    const isValidCPF = (cpf) => {
        const cleanCPF = cpf.replace(/\D/g, '');
        return cleanCPF.length === 11;
    };

    const handleProcessCheckout = async (e) => {
        e.preventDefault();

        // Basic Validation
        if (!formData.fullName || !formData.email || !formData.street || !formData.number || !formData.city || !formData.state) {
            toast.error('Por favor, preencha todos os campos obrigat├│rios do endere├ºo.');
            return;
        }

        if (!isValidEmail(formData.email)) {
            toast.error('E-mail inv├ílido. Certifique-se de que ele termina com seu provedor (ex: .com)');
            return;
        }

        if (!isValidCPF(formData.cpf)) {
            toast.error('O CPF inserido ├⌐ inv├ílido.');
            return;
        }

        setIsLoading(true);

        try {
            // Save data locally if needed or attach to user
            localStorage.setItem('gusli_checkout_info', JSON.stringify(formData));

            // Create Preference directly
            const prefRes = await axios.post('http://localhost:3001/api/create_preference', {
                cartItems,
                payerInfo: formData
            });
            if (prefRes.data.init_point) {
                // Redirect user to Mercado Pago to finalize payment
                window.location.href = prefRes.data.init_point;
                return;
            }
        } catch (error) {
            console.error("Mercado Pago checkout error:", error);
            toast.error("Processando via sistema de fallback seguro...", { duration: 4000 });

            // Fallback: Finalize order on backend if MP fails
            const storedUser = localStorage.getItem('gusli_user');
            const user = storedUser ? JSON.parse(storedUser) : null;

            await axios.post('http://localhost:3001/api/checkout', {
                userId: user ? user.id : null,
                total: cartTotal,
                items: cartItems
            });

            clearCart();
            navigate('/account'); // Send to their account or success page
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gusli-bg pt-32 pb-24 px-6 md:px-12  group/page flex flex-col items-center">

            <div className="w-full max-w-[1600px] flex flex-col lg:flex-row gap-16 lg:gap-24 relative">

                {/* Left Form Section (Editorial) */}
                <div className="flex-1">
                    <button
                        onClick={() => navigate(-1)}
                        className="flex items-center gap-4 text-black hover:text-black mb-12 transition-colors font-bold uppercase text-[10px] tracking-[0.3em] "
                    >
                        <ArrowLeft size={16} /> [ Retornar ]
                    </button>

                    <h1 className="font-display text-6xl md:text-8xl text-black uppercase tracking-tighter leading-none mb-4">Checkout</h1>
                    <p className="text-black text-xs uppercase tracking-[0.3em] font-bold mb-16 border-b border-black/20 pb-12">
                        Autoriza├º├úo de Envio e Transa├º├úo
                    </p>

                    <form onSubmit={handleProcessCheckout} className="space-y-12 max-w-2xl">
                        <div className="flex flex-col gap-10">
                            {/* Identifica├º├úo */}
                            <div className="space-y-8 border-b border-black/10 pb-12">
                                <h3 className="font-display text-2xl text-black uppercase tracking-widest">Identifica├º├úo</h3>

                                <div>
                                    <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">Nome Completo *</label>
                                    <input required type="text" name="fullName" value={formData.fullName} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="Primeiro e ├Ültimo Nome" />
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <div>
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">E-mail *</label>
                                        <input required type="email" name="email" value={formData.email} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="contato@servidor.com" />
                                    </div>
                                    <div>
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">Cadastro (CPF) *</label>
                                        <input required type="text" name="cpf" value={formData.cpf} onChange={handleChange} maxLength="14" className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="000.000.000-00" />
                                    </div>
                                </div>
                            </div>

                            {/* Entrega */}
                            <div className="space-y-8">
                                <h3 className="font-display text-2xl text-black uppercase tracking-widest">Destino</h3>

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                    <div>
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">CEP *</label>
                                        <input required type="text" name="zipCode" value={formData.zipCode} onChange={handleChange} onBlur={handleZipCodeBlur} maxLength="9" className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="00000-000" />
                                    </div>
                                    <div className="md:col-span-2">
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">Logradouro *</label>
                                        <input required type="text" name="street" value={formData.street} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="Avenida ou Rua" />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                    <div>
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">N├║mero *</label>
                                        <input required type="text" name="number" value={formData.number} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="123" />
                                    </div>
                                    <div className="md:col-span-2">
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">Complemento / Local</label>
                                        <input type="text" name="complement" value={formData.complement} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="Opcional" />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                                    <div>
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">Bairro *</label>
                                        <input required type="text" name="neighborhood" value={formData.neighborhood} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="Seu Bairro" />
                                    </div>
                                    <div>
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">Localidade *</label>
                                        <input required type="text" name="city" value={formData.city} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="Cidade" />
                                    </div>
                                    <div>
                                        <label className="block text-[10px] font-bold text-black mb-2 uppercase tracking-[0.3em]">Estado *</label>
                                        <input required type="text" name="state" value={formData.state} onChange={handleChange} className="w-full bg-transparent border-b border-black/30 py-4 text-xl font-medium text-black focus:outline-none focus:border-white transition-colors  placeholder-black/50" placeholder="UF" />
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="pt-16 mt-16 border-t border-black/20 hidden md:block">
                            {/* Desktop Button Location */}
                            <button
                                type="submit"
                                disabled={isLoading}
                                className="w-full bg-black text-gusli-bg py-8 font-sans text-4xl font-bold flex justify-center items-center gap-6 disabled:opacity-50 disabled:cursor-not-allowed tracking-tight transition-colors border border-transparent hover:bg-white hover:text-[#12271D] hover:border-[#12271D] rounded-full"
                            >
                                {isLoading ? 'Processando...' : 'Concluir Pedido'}
                                {!isLoading && <ArrowRight size={32} className="group-hover:translate-x-4 transition-transform" />}
                            </button>
                            <div className="flex items-center justify-center gap-2 mt-6 text-black text-[10px] font-bold uppercase tracking-[0.2em]">
                                <ShieldCheck size={14} /> Sistema Criptografado Mercado Pago
                            </div>
                        </div>
                    </form>
                </div>

