                        <div className="w-full md:w-auto">
                            <label className="block text-[10px] font-bold text-black mb-3 tracking-wide">Variantes / Acabamento</label>
                            <select
                                value={selectedVariation}
                                onChange={(e) => setSelectedVariation(e.target.value)}
